  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"Her smile was as bright as the sun." is an example of:', '["simile","hyperbole","personification","metaphor"]', 0, 'It compares using "like"/"as" — a simile.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"He was as busy as a bee." is an example of:', '["personification","hyperbole","simile","metaphor"]', 2, 'It compares using "like"/"as" — a simile.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"Time is a thief." is an example of:', '["hyperbole","metaphor","personification","simile"]', 1, 'It calls one thing another — a metaphor.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The thunder grumbled in the distance." is an example of:', '["metaphor","simile","personification","hyperbole"]', 2, 'It gives human traits to a non-human thing — personification.', 15),
